import React from 'react';
import { useLocation, useNavigate, Link } from 'react-router-dom';
import ConfidenceBar from '../components/ConfidenceBar';
import BreedCard from '../components/BreedCard';
import './ResultPage.css';

export default function ResultPage() {
  const { state } = useLocation();
  const navigate  = useNavigate();

  // Guard: if user navigates directly without data, send home
  if (!state?.result) {
    return (
      <div className="result-page">
        <div className="result-empty container">
          <p>No prediction found.</p>
          <Link to="/" className="btn-primary" style={{ marginTop: 20 }}>
            Go back home
          </Link>
        </div>
      </div>
    );
  }

  const { result, previewUrl } = state;
  const { breed, confidence, details } = result;

  return (
    <main className="result-page">
      <div className="result-container container">

        {/* ── Back button ── */}
        <button className="btn-ghost back-btn" onClick={() => navigate('/')}>
          ← Identify Another
        </button>

        <div className="result-grid">

          {/* ── Left: image + prediction ── */}
          <div className="result-left fade-up">
            {/* Image */}
            <div className="result-image-wrap card">
              {previewUrl ? (
                <img
                  src={previewUrl}
                  alt={`Uploaded — identified as ${breed}`}
                  className="result-image"
                />
              ) : (
                <div className="result-image-placeholder">
                  No image preview
                </div>
              )}
            </div>

            {/* Prediction badge */}
            <div className="prediction-badge card">
              <div className="prediction-badge-header">
                <span className="prediction-label">Identified Breed</span>
                <span className="prediction-tag">AI Prediction</span>
              </div>
              <h2 className="prediction-breed">{breed}</h2>
              <ConfidenceBar value={confidence} />
            </div>
          </div>

          {/* ── Right: breed details ── */}
          <div className="result-right fade-up-2">
            <div className="details-header">
              <h3 className="details-title">Breed Profile</h3>
              <p className="details-sub">
                Detailed data for <strong>{breed}</strong> sourced from our breed database
              </p>
            </div>

            <div className="card details-card">
              <BreedCard details={details} />
            </div>

            {/* Actions */}
            <div className="result-actions">
              <button
                className="btn-primary"
                onClick={() => navigate('/')}
              >
                Identify Another
              </button>
              <Link to="/history" className="btn-ghost">
                View History
              </Link>
            </div>

            {/* Disclaimer */}
            <p className="result-disclaimer">
              ℹ Predictions are generated by an AI model and may not be 100% accurate.
              Always verify with an expert for critical decisions.
            </p>
          </div>

        </div>
      </div>
    </main>
  );
}
